class Solution {
public:
    bool detectCapitalUse(string word) {
        bool allUpper = true, allLower = true, firstUpper = true;
        for (char c : word) {
            if (isupper(c)) {
                if (!allUpper) return false;
                allLower = false;
            } else {
                allUpper = false;
                if (firstUpper) firstUpper = false;
            }
        }
        return allUpper || allLower;
    }
};
